-- Gmail-specific dark mode fix.
-- Gmail ignores bgcolor/!important overrides during its dark mode transform,
-- BUT it does honour <style> blocks with the "u+.body" selector hack —
-- a selector that ONLY matches inside Gmail's rendering context.
-- We add CSS classes to every element and target them all from the style block.
-- Combined with data-ogsb (Outlook) and @media prefers-color-scheme (Apple Mail).

UPDATE email_templates SET
  body_html = '<style type="text/css">u+.body .em-bg{background-color:#09090b !important;}u+.body .em-td{background-color:#09090b !important;}u+.body .em-panel{background-color:#18181b !important;}u+.body .em-h{color:#fafafa !important;}u+.body .em-p{color:#a1a1aa !important;}u+.body .em-sm{color:#71717a !important;}u+.body .em-green{color:#34d399 !important;}u+.body .em-foot{color:#3f3f46 !important;}u+.body .em-strong{color:#fafafa !important;}@media (prefers-color-scheme:dark){.em-bg{background-color:#09090b !important;}.em-td{background-color:#09090b !important;}.em-panel{background-color:#18181b !important;}.em-h{color:#fafafa !important;}.em-p{color:#a1a1aa !important;}.em-sm{color:#71717a !important;}.em-green{color:#34d399 !important;}.em-foot{color:#3f3f46 !important;}.em-strong{color:#fafafa !important;}}</style><table class="em-bg" width="100%" cellpadding="0" cellspacing="0" bgcolor="#09090b" data-ogsb="#09090b" style="background-color:#09090b !important;"><tr><td class="em-td" align="center" bgcolor="#09090b" data-ogsb="#09090b" style="background-color:#09090b !important;padding:40px 20px;font-family:''Red Hat Display'',Arial,sans-serif;"><table class="em-bg" cellpadding="0" cellspacing="0" bgcolor="#09090b" data-ogsb="#09090b" style="width:100%;max-width:480px;background-color:#09090b !important;border-radius:16px;"><tr><td class="em-td" align="center" bgcolor="#09090b" data-ogsb="#09090b" style="background-color:#09090b !important;padding:40px 32px 24px;"><img src="https://dash.complerer.com/logo-white.png" alt="Complerer" height="28" /></td></tr><tr><td class="em-td" bgcolor="#09090b" data-ogsb="#09090b" style="background-color:#09090b !important;padding:0 32px;"><h2 class="em-h" style="color:#fafafa !important;font-size:20px;font-weight:700;margin:0 0 8px;">Verify your email</h2><p class="em-p" style="color:#a1a1aa !important;font-size:14px;line-height:1.6;margin:0 0 24px;">Enter this code to sign in to Complerer:</p><table class="em-panel" width="100%" cellpadding="0" cellspacing="0" bgcolor="#18181b" data-ogsb="#18181b" style="background-color:#18181b !important;border:1px solid #27272a;border-radius:12px;"><tr><td class="em-panel" align="center" bgcolor="#18181b" data-ogsb="#18181b" style="background-color:#18181b !important;padding:24px;"><span class="em-green" data-ogsc="#34d399" style="font-size:36px;font-weight:700;letter-spacing:10px;color:#34d399 !important;">{{code}}</span></td></tr></table><p class="em-sm" style="color:#71717a !important;font-size:12px;line-height:1.6;margin:16px 0 32px;">This code expires in 10 minutes. If you did not request this, please ignore this email.</p></td></tr><tr><td class="em-td" align="center" bgcolor="#09090b" data-ogsb="#09090b" style="background-color:#09090b !important;padding:16px 32px 40px;border-top:1px solid #1c1c1f;"><p class="em-foot" style="color:#3f3f46 !important;font-size:11px;margin:0;">Complerer · Compliance Platform</p></td></tr></table></td></tr></table>',
  updated_at = datetime('now')
WHERE slug = 'otp-verification';

